/**
 * Webhook notification adapter.
 *
 * Formats notification payloads as JSON and POSTs them to a configured URL.
 * In this implementation, requests are collected in a delivery log that can
 * be inspected (useful for testing and local development). A production
 * version would use a real HTTP client.
 */

import { Logger } from '../utils/logger.js';
import type { NotificationAdapter, NotificationPayload } from './notification-adapter.js';

export interface WebhookDelivery {
  url: string;
  payload: WebhookPayloadBody;
  sentAt: Date;
}

export interface WebhookPayloadBody {
  recipient: string;
  subject: string;
  body: string;
  timestamp: string;
}

export interface WebhookAdapterOptions {
  /** The URL to POST webhook payloads to. */
  url: string;
  /** Optional secret for signing payloads. */
  secret?: string;
}

export class WebhookAdapter implements NotificationAdapter {
  readonly name = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private deliveries: WebhookDelivery[] = [];
  private url: string;
  private secret: string | undefined;

  constructor(options: WebhookAdapterOptions) {
    this.url = options.url;
    this.secret = options.secret;
  }

  /**
   * Format a notification payload into the JSON body sent via webhook.
   */
  formatPayload(payload: NotificationPayload): WebhookPayloadBody {
    return {
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Send a notification as a webhook POST.
   */
  send(payload: NotificationPayload): boolean {
    const formatted = this.formatPayload(payload);

    const delivery: WebhookDelivery = {
      url: this.url,
      payload: formatted,
      sentAt: new Date(),
    };

    this.deliveries.push(delivery);
    this.logger.info(`Webhook delivered to ${this.url}: "${payload.subject}"`);
    return true;
  }

  /** Get all deliveries (for testing / inspection). */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /** Clear the delivery log. */
  clearDeliveries(): void {
    this.deliveries = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook-adapter.js';
import type { NotificationPayload } from '../../src/adapters/notification-adapter.js';

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  beforeEach(() => {
    adapter = new WebhookAdapter({
      url: 'https://hooks.example.com/notify',
      secret: 'test-secret',
    });
  });

  describe('formatPayload', () => {
    it('should include recipient, subject, body, and timestamp', () => {
      const payload: NotificationPayload = {
        recipient: 'user-1',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      };

      const formatted = adapter.formatPayload(payload);

      expect(formatted.recipient).toBe('user-1');
      expect(formatted.subject).toBe('Order Confirmation');
      expect(formatted.body).toBe('Your order has been placed.');
      expect(formatted.timestamp).toBeDefined();
      expect(() => new Date(formatted.timestamp)).not.toThrow();
    });

    it('should produce a valid ISO timestamp', () => {
      const formatted = adapter.formatPayload({
        recipient: 'user-1',
        subject: 's',
        body: 'b',
      });

      const parsed = new Date(formatted.timestamp);
      expect(parsed.toISOString()).toBe(formatted.timestamp);
    });
  });

  describe('send', () => {
    it('should add delivery to log and return true', () => {
      const payload: NotificationPayload = {
        recipient: 'user-1',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      };

      const result = adapter.send(payload);

      expect(result).toBe(true);
      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://hooks.example.com/notify');
      expect(deliveries[0]?.payload.recipient).toBe('user-1');
      expect(deliveries[0]?.payload.subject).toBe('Order Confirmation');
      expect(deliveries[0]?.payload.body).toBe('Your order has been placed.');
      expect(deliveries[0]?.sentAt).toBeInstanceOf(Date);
    });

    it('should accumulate multiple deliveries', () => {
      adapter.send({ recipient: 'a', subject: 's1', body: 'b1' });
      adapter.send({ recipient: 'b', subject: 's2', body: 'b2' });

      expect(adapter.getDeliveries()).toHaveLength(2);
    });
  });

  describe('delivery management', () => {
    it('should clear deliveries', () => {
      adapter.send({ recipient: 'a', subject: 's', body: 'b' });
      adapter.clearDeliveries();
      expect(adapter.getDeliveries()).toHaveLength(0);
    });

    it('should return a copy of the deliveries', () => {
      adapter.send({ recipient: 'a', subject: 's', body: 'b' });
      const deliveries = adapter.getDeliveries();
      deliveries.pop();
      expect(adapter.getDeliveries()).toHaveLength(1);
    });
  });

  describe('adapter interface', () => {
    it('should have name "webhook"', () => {
      expect(adapter.name).toBe('webhook');
    });

    it('should work without a secret', () => {
      const simpleAdapter = new WebhookAdapter({ url: 'https://hooks.example.com/test' });
      simpleAdapter.send({ recipient: 'x', subject: 'hi', body: 'hello' });
      expect(simpleAdapter.getDeliveries()).toHaveLength(1);
    });
  });
});

